87	llm_chat_template llm_chat_detect_template(const std::string & tmpl) {
88	    try {
89	        return llm_chat_template_from_str(tmpl);
90	    } catch (const std::out_of_range &) {
91	        // ignore
92	    }
93	
94	    auto tmpl_contains = [&tmpl](const char * haystack) -> bool {
95	        return tmpl.find(haystack) != std::string::npos;
96	    };
97	    if (tmpl_contains("<|im_start|>")) {
98	        return tmpl_contains("<|im_sep|>")
99	            ? LLM_CHAT_TEMPLATE_PHI_4
100	            : tmpl_contains("<end_of_utterance>")
101	                ? LLM_CHAT_TEMPLATE_SMOLVLM // SmolVLM uses <|im_start|> as BOS, but it is NOT chatml
102	                : LLM_CHAT_TEMPLATE_CHATML;
103	    } else if (tmpl.find("mistral") == 0 || tmpl_contains("[INST]")) {
104	        if (tmpl_contains("[SYSTEM_PROMPT]")) {
105	            return LLM_CHAT_TEMPLATE_MISTRAL_V7;
106	        } else if (
107	            // catches official 'v1' template
108	            tmpl_contains("' [INST] ' + system_message")
109	            // catches official 'v3' and 'v3-tekken' templates
110	            || tmpl_contains("[AVAILABLE_TOOLS]")
111	        ) {
112	            // Official mistral 'v1', 'v3' and 'v3-tekken' templates
113	            // See: https://github.com/mistralai/cookbook/blob/main/concept-deep-dive/tokenization/chat_templates.md
114	            // See: https://github.com/mistralai/cookbook/blob/main/concept-deep-dive/tokenization/templates.md
115	            if (tmpl_contains(" [INST]")) {
116	                return LLM_CHAT_TEMPLATE_MISTRAL_V1;
117	            } else if (tmpl_contains("\"[INST]\"")) {
118	                return LLM_CHAT_TEMPLATE_MISTRAL_V3_TEKKEN;
119	            }
120	            return LLM_CHAT_TEMPLATE_MISTRAL_V3;
121	        } else {
122	            // llama2 template and its variants
123	            // [variant] support system message
124	            // See: https://huggingface.co/blog/llama2#how-to-prompt-llama-2
125	            bool support_system_message = tmpl_contains("<<SYS>>");
126	            bool add_bos_inside_history = tmpl_contains("bos_token + '[INST]");
127	            bool strip_message = tmpl_contains("content.strip()");
128	            if (strip_message) {
129	                return LLM_CHAT_TEMPLATE_LLAMA_2_SYS_STRIP;
130	            } else if (add_bos_inside_history) {
131	                return LLM_CHAT_TEMPLATE_LLAMA_2_SYS_BOS;
132	            } else if (support_system_message) {
133	                return LLM_CHAT_TEMPLATE_LLAMA_2_SYS;
134	            } else {
135	                return LLM_CHAT_TEMPLATE_LLAMA_2;
136	            }
137	        }
138	    } else if (tmpl_contains("<|assistant|>") && tmpl_contains("<|end|>")) {
139	        return LLM_CHAT_TEMPLATE_PHI_3;
140	    } else if (tmpl_contains("[gMASK]<sop>")) {
141	        return LLM_CHAT_TEMPLATE_CHATGLM_4;
142	    } else if (tmpl_contains("<|assistant|>") && tmpl_contains("<|user|>")) {
143	        if (tmpl_contains("<|tool_declare|>")) {
144	            return LLM_CHAT_TEMPLATE_EXAONE_MOE;
145	        }
146	        return tmpl_contains("</s>") ? LLM_CHAT_TEMPLATE_FALCON_3 : LLM_CHAT_TEMPLATE_GLMEDGE;
147	    } else if (tmpl_contains("<|{{ item['role'] }}|>") && tmpl_contains("<|begin_of_image|>")) {
148	        return LLM_CHAT_TEMPLATE_GLMEDGE;
149	    } else if (tmpl_contains("<|user|>") && tmpl_contains("<|endoftext|>")) {
150	        return LLM_CHAT_TEMPLATE_ZEPHYR;
151	    } else if (tmpl_contains("bos_token + message['role']")) {
152	        return LLM_CHAT_TEMPLATE_MONARCH;
153	    } else if (tmpl_contains("<start_of_turn>")) {
154	        return LLM_CHAT_TEMPLATE_GEMMA;
155	    } else if (tmpl_contains("'\\n\\nAssistant: ' + eos_token")) {
156	        // OrionStarAI/Orion-14B-Chat
157	        return LLM_CHAT_TEMPLATE_ORION;
158	    } else if (tmpl_contains("GPT4 Correct ")) {
159	        // openchat/openchat-3.5-0106
160	        return LLM_CHAT_TEMPLATE_OPENCHAT;
161	    } else if (tmpl_contains("USER: ") && tmpl_contains("ASSISTANT: ")) {
162	        // eachadea/vicuna-13b-1.1 (and Orca variant)
163	        if (tmpl_contains("SYSTEM: ")) {
164	            return LLM_CHAT_TEMPLATE_VICUNA_ORCA;
165	        }
166	        return LLM_CHAT_TEMPLATE_VICUNA;
167	    } else if (tmpl_contains("### Instruction:") && tmpl_contains("<|EOT|>")) {
168	        // deepseek-ai/deepseek-coder-33b-instruct
169	        return LLM_CHAT_TEMPLATE_DEEPSEEK;
170	    } else if (tmpl_contains("<|START_OF_TURN_TOKEN|>") && tmpl_contains("<|USER_TOKEN|>")) {
171	        // CohereForAI/c4ai-command-r-plus
172	        return LLM_CHAT_TEMPLATE_COMMAND_R;
173	    } else if (tmpl_contains("<|start_header_id|>") && tmpl_contains("<|end_header_id|>")) {
174	        return LLM_CHAT_TEMPLATE_LLAMA_3;
175	    } else if (tmpl_contains("[gMASK]sop")) {
176	        // chatglm3-6b
177	        return LLM_CHAT_TEMPLATE_CHATGLM_3;
178	    } else if (tmpl_contains(LU8("<用户>"))) {
179	        // MiniCPM-3B-OpenHermes-2.5-v2-GGUF
180	        return LLM_CHAT_TEMPLATE_MINICPM;
181	    } else if (tmpl_contains("'Assistant: ' + message['content'] + eos_token")) {
182	        return LLM_CHAT_TEMPLATE_DEEPSEEK_2;
183	    } else if (tmpl_contains(LU8("<｜Assistant｜>")) && tmpl_contains(LU8("<｜User｜>")) && tmpl_contains(LU8("<｜end▁of▁sentence｜>"))) {
184	        return LLM_CHAT_TEMPLATE_DEEPSEEK_3;
185	    } else if (tmpl_contains("[|system|]") && tmpl_contains("[|assistant|]") && tmpl_contains("[|endofturn|]")) {
186	        if (tmpl_contains("[|tool|]")) {
187	            return LLM_CHAT_TEMPLATE_EXAONE_4;
188	        }
189	        // ref: https://huggingface.co/LGAI-EXAONE/EXAONE-3.0-7.8B-Instruct/discussions/8#66bae61b1893d14ee8ed85bb
190	        // EXAONE-3.0-7.8B-Instruct
191	        return LLM_CHAT_TEMPLATE_EXAONE_3;
192	    } else if (tmpl_contains("rwkv-world") || tmpl_contains("{{- 'User: ' + message['content']|trim + '\\n\\n' -}}")) {
193	        return LLM_CHAT_TEMPLATE_RWKV_WORLD;
194	    } else if (tmpl_contains("<|start_of_role|>")) {
195	        if (tmpl_contains("<tool_call>") || tmpl_contains("<tools>")) {
196	            return LLM_CHAT_TEMPLATE_GRANITE_4_0;
197	        }
198	        return LLM_CHAT_TEMPLATE_GRANITE_3_X;
199	    } else if (tmpl_contains("message['role'] + additional_special_tokens[0] + message['content'] + additional_special_tokens[1]")) {
200	        return LLM_CHAT_TEMPLATE_GIGACHAT;
201	    } else if (tmpl_contains("<|role_start|>")) {
202	        return LLM_CHAT_TEMPLATE_MEGREZ;
203	    } else if (tmpl_contains(" Ассистент:")) {
204	        return LLM_CHAT_TEMPLATE_YANDEX;
205	    } else if (tmpl_contains("<role>ASSISTANT</role>") && tmpl_contains("'HUMAN'")) {
206	        return LLM_CHAT_TEMPLATE_BAILING;
207	    } else if (tmpl_contains("<role>ASSISTANT</role>") && tmpl_contains("\"HUMAN\"") && tmpl_contains("<think>")) {
208	        return LLM_CHAT_TEMPLATE_BAILING_THINK;
209	    } else if (tmpl_contains("<role>ASSISTANT</role>") && tmpl_contains("<role>HUMAN</role>") && tmpl_contains("<|role_end|>")) {
210	        return LLM_CHAT_TEMPLATE_BAILING2;
211	    } else if (tmpl_contains("<|header_start|>") && tmpl_contains("<|header_end|>")) {
212	        return LLM_CHAT_TEMPLATE_LLAMA4;
213	    } else if (tmpl_contains("<|endofuserprompt|>")) {
214	        return LLM_CHAT_TEMPLATE_DOTS1;
215	    } else if (tmpl_contains("<|extra_0|>") && tmpl_contains("<|extra_4|>")) {
216	        return LLM_CHAT_TEMPLATE_HUNYUAN_MOE;
217	    } else if (tmpl_contains("<|start|>") && tmpl_contains("<|channel|>")) {
218	        return LLM_CHAT_TEMPLATE_OPENAI_MOE;
219	    } else if (tmpl_contains("<｜hy_Assistant｜>") && tmpl_contains("<｜hy_place▁holder▁no▁3｜>")) {
220	        return LLM_CHAT_TEMPLATE_HUNYUAN_DENSE;
221	    } else if (tmpl_contains("<|im_assistant|>assistant<|im_middle|>")) {
222	        return LLM_CHAT_TEMPLATE_KIMI_K2;
223	    } else if (tmpl_contains("<seed:bos>")) {
224	        return LLM_CHAT_TEMPLATE_SEED_OSS;
225	    } else if (tmpl_contains("'Assistant: '  + message['content'] + '<|separator|>")) {
226	        return LLM_CHAT_TEMPLATE_GROK_2;
227	    } else if (tmpl_contains(LU8("[unused9]系统：[unused10]"))) {
228	        return LLM_CHAT_TEMPLATE_PANGU_EMBED;
229	    } else if (tmpl_contains("<|begin|>") && tmpl_contains("<|end|>") && tmpl_contains("<|content|>")) {
230	        return LLM_CHAT_TEMPLATE_SOLAR_OPEN;
231	    }
232	    return LLM_CHAT_TEMPLATE_UNKNOWN;
233	}
