1807	static common_chat_params common_chat_templates_apply_legacy(const struct common_chat_templates *        tmpls,
1808	                                                             const struct common_chat_templates_inputs & inputs) {
1809	    size_t                          alloc_size = 0;
1810	    std::vector<llama_chat_message> chat;
1811	    std::vector<std::string>        contents;
1812	
1813	    for (const auto & msg : inputs.messages) {
1814	        auto content = msg.content;
1815	        for (const auto & part : msg.content_parts) {
1816	            if (part.type != "text" && part.type != "media_marker") {
1817	                LOG_WRN("Ignoring non-text content part: %s\n", part.type.c_str());
1818	                continue;
1819	            }
1820	            if (!content.empty()) {
1821	                content += "\n";
1822	                ;
1823	            }
1824	            content += part.text;
1825	        }
1826	        contents.emplace_back(std::move(content));
1827	    }
1828	    for (size_t i = 0; i < contents.size(); ++i) {
1829	        const auto & msg     = inputs.messages[i];
1830	        const auto & content = contents[i];
1831	        chat.push_back({ msg.role.c_str(), content.c_str() });
1832	        size_t msg_size = msg.role.size() + content.size();
1833	        alloc_size += msg_size + (msg_size / 4);  // == msg_size * 1.25 but avoiding float ops
1834	    }
1835	
1836	    std::vector<char> buf(alloc_size);
1837	
1838	    // run the first time to get the total output length
1839	    const auto & src = tmpls->template_default->source();
1840	    int32_t      res = llama_chat_apply_template(src.c_str(), chat.data(), chat.size(), inputs.add_generation_prompt,
1841	                                                 buf.data(), buf.size());
1842	
1843	    // error: chat template is not supported
1844	    if (res < 0) {
1845	        // if the custom "tmpl" is not supported, we throw an error
1846	        // this is a bit redundant (for good), since we're not sure if user validated the custom template with llama_chat_verify_template()
1847	        throw std::runtime_error("this custom template is not supported, try using --jinja");
1848	    }
1849	
1850	    // if it turns out that our buffer is too small, we resize it
1851	    if ((size_t) res > buf.size()) {
1852	        buf.resize(res);
1853	        res = llama_chat_apply_template(src.c_str(), chat.data(), chat.size(), inputs.add_generation_prompt, buf.data(),
1854	                                        buf.size());
1855	    }
1856	
1857	    // for safety, we check the result again
1858	    if (res < 0 || (size_t) res > buf.size()) {
1859	        throw std::runtime_error("failed to apply chat template, try using --jinja");
1860	    }
1861	
1862	    common_chat_params params;
1863	    params.prompt = std::string(buf.data(), res);
1864	    if (!inputs.json_schema.empty()) {
1865	        params.grammar = json_schema_to_grammar(json::parse(inputs.json_schema));
1866	    } else {
1867	        params.grammar = inputs.grammar;
1868	    }
1869	    return params;
1870	}
